```python
def _render_progress_html(current_step: int, error: bool = False, detail_msg: str = "") -> str:
    """
    current_step: 
    0 = Data Preview
    1 = Processing Plan
    2 = Code Generation
    3 = Code Execution
    4 = Done
    """
    steps = ["Data Preview", "Processing Plan", "Code Generation", "Code Execution"]

    icons_html = '<div class="step-row">'
    for idx, name in enumerate(steps):
        if idx < current_step:
            status_class = "done"
            icon = "✓"
        elif idx == current_step:
            if error:
                status_class = "error"
                icon = "✕"
            elif current_step == 4: # All done
                 status_class = "done"
                 icon = "✓"
            else:
                status_class = "active"
                icon = "⋯"
        else:
            status_class = ""
            icon = str(idx + 1)

        icons_html += f"""
        <div class="step-item {status_class}">
            <div class="step-icon">{icon}</div>
            <div>{name}</div>
        </div>
        """
        if idx < len(steps) - 1:
            icons_html += '<div class="step-arrow">➜</div>'
    icons_html += '</div>'

    text_html = f'<div class="step-status-text">{detail_msg}</div>'
    return f'<div class="step-container">{icons_html}{text_html}</div>'
