def _execute_generated_code_remote(code_text: str, timeout: int = RUN_CODE_TIMEOUT) -> Tuple[str, str, str]:
    # ... (前面的请求逻辑保持不变) ...
    if not code_text or not code_text.strip():
        return "", "", "No code to run."
    try:
        # ... request logic ...
        headers = {}
        if RUN_CODE_KEY: headers["x-forward-key"] = RUN_CODE_KEY
        resp = requests.post(RUN_CODE_URL, json={"code": code_text, "timeout": timeout}, headers=headers, timeout=timeout+10)
        resp.raise_for_status()
        data = resp.json() if resp.content else {}
    except Exception as e:
        return "", "", f"Run error: {e}"

    # ... (Logs parsing 逻辑不变) ...
    # 简化 logs 解析，因为我们不在 UI 显示 logs 了，但函数仍需返回以保持结构
    logs_txt = "Logs hidden"

    # 2. Parse Evaluation Table -> Renamed to Processed Training Data
    data_scores = data.get("data_scores") or []
    data_score_error = data.get("data_score_error")
    eval_md = ""

    if data_scores:
        formatted_scores = []
        for s in data_scores:
            formatted_scores.append({
                "#": s.get("index"),
                "Score": f"{s.get('score', 0):.2f}",
                # "Judgement": s.get("judgement", ""), # 可以选择隐藏 judgement 让表格更紧凑
                "User": _truncate_text(s.get("question_preview", ""), 120),
                "Assistant": _truncate_text(s.get("answer_preview", ""), 120)
            })
        # 修改标题
        eval_md = _render_markdown_table(formatted_scores, title="Processed Training Data (Top Samples)")
    elif data_score_error:
        eval_md = f"**Data Processing Error:** {data_score_error}"
    else:
        eval_md = "No data returned from execution."

    # 3. Processed Preview (Unused in new UI but kept for compatibility)
    preview_md = "" 

    return eval_md, preview_md, logs_txt
