def _run_full_automation(
    task_description: str,
    benchmark_name: str,
    benchmark_description: str,
    dataset_ids_table: List[List[str]]
):
    """
    Generator that runs the entire pipeline: Preview -> Plan -> Code -> Execute.
    Yields: (status_html, preview_md, plan_md, plan_raw, code_src, eval_md)
    """
    # 占位符
    empty = ""
    loading_md = "_Loading..._"

    # --- Step 1: Data Preview ---
    yield (
        gr.update(value=_render_progress_html(0, detail_msg="Fetching dataset info..."), visible=True),
        loading_md, empty, empty, empty, empty
    )

    # 执行 Preview
    preview_md = _preview_dataset(dataset_ids_table)
    if "Preview error" in preview_md or "Loading Errors" in preview_md:
         # 如果预览严重失败，可能仍继续尝试，或者报错。这里继续，但在表格中显示错误。
         pass

    # --- Step 2: Planning ---
    yield (
        gr.update(value=_render_progress_html(1, detail_msg="Designing data recipe...")),
        preview_md, loading_md, empty, empty, empty
    )

    # 构建 Sample
    sample, error = _build_sample_from_inputs(task_description, benchmark_name, benchmark_description, dataset_ids_table)
    if error:
        err_html = _render_progress_html(1, error=True, detail_msg=f"Error: {error}")
        yield (gr.update(value=err_html), preview_md, f"❌ {error}", f"❌ {error}", empty, empty)
        return

    # 生成 Plan
    plan_text = _generate_plan_from_sample(sample)
    if plan_text.startswith("Planner error"):
        err_html = _render_progress_html(1, error=True, detail_msg="Planner failed")
        yield (gr.update(value=err_html), preview_md, plan_text, plan_text, empty, empty)
        return

    # --- Step 3: Coding ---
    yield (
        gr.update(value=_render_progress_html(2, detail_msg="Generating Python script...")),
        preview_md, plan_text, plan_text, loading_md, empty
    )

    # 生成 Code
    code_text = _generate_code_from_plan(sample["datasets"], plan_text)
    if code_text.startswith("Coder error"):
        err_html = _render_progress_html(2, error=True, detail_msg="Coder failed")
        yield (gr.update(value=err_html), preview_md, plan_text, plan_text, code_text, empty)
        return

    # --- Step 4: Execution ---
    yield (
        gr.update(value=_render_progress_html(3, detail_msg="Executing code on remote runner...")),
        preview_md, plan_text, plan_text, code_text, "_Processing data... this may take a moment_"
    )

    # 执行 Code
    eval_md, _, _ = _execute_generated_code_remote(code_text)

    # --- Done ---
    # 隐藏进度条，显示最终结果
    yield (
        gr.update(visible=False),
        preview_md, plan_text, plan_text, code_text, eval_md
    )
